{"action":"tool_call","tool_name":"write_file","arguments":{"path":"src/csv_projection.py","content":"import csv
import io
def _columns(value):
    if isinstance(value, (str, bytes)): raise ValueError('non-string iterable required')
    try: result = list(value)
    except TypeError as exc: raise ValueError('iterable required') from exc
    if not result or any(not isinstance(item, str) or not item for item in result) or len(set(result)) != len(result): raise ValueError('invalid columns')
    return result
def project_csv(text: str, columns: list[str]) -> str:
    if not isinstance(text, str) or '\x00' in text: raise ValueError('invalid text')
    try: rows = list(csv.reader(io.StringIO(text, newline=''), strict=True))
    except csv.Error as exc: raise ValueError('malformed CSV') from exc
    if not rows or not rows[0] or any(not name for name in rows[0]) or len(set(rows[0])) != len(rows[0]): raise ValueError('invalid header')
    header = rows[0]
    if any(len(row) != len(header) for row in rows[1:]): raise ValueError('ragged row')
    selected = _columns(columns)
    if any(column not in header for column in selected): raise ValueError('unknown column')
    indices = [header.index(column) for column in selected]
    output = io.StringIO(newline='')
    csv.writer(output, lineterminator='\n').writerows([[row[index] for index in indices] for row in rows])
    return output.getvalue()
